drop table if exists public."settlement_expenses" cascade;
create table public."settlement_expenses" (
  "id" bigint,
  "work_name" text,
  "expense_amount" bigint,
  "expense_date" date,
  "expense_type" text,
  "created_at" timestamptz
);

drop table if exists public."settlement_payments" cascade;
create table public."settlement_payments" (
  "id" bigint,
  "work_name" text,
  "payment_type" text,
  "payment_detail" text,
  "payment_amount" bigint,
  "payment_date" text,
  "payment_method" text,
  "approval_number" text,
  "merchant_number" text,
  "card_number" text,
  "created_at" timestamptz,
  "invoice_issued" boolean,
  "claim_date" text,
  "payment_status" text,
  "claim_amount" bigint
);

drop table if exists public."vehicle_catalog" cascade;
create table public."vehicle_catalog" (
  "id" bigint,
  "maker" text,
  "model" text,
  "color_code" text,
  "is_active" boolean,
  "created_at" timestamptz,
  "updated_at" timestamptz
);

drop table if exists public."vehicle_color_codes" cascade;
create table public."vehicle_color_codes" (
  "id" bigint,
  "model_id" bigint,
  "code" text,
  "color_name" text,
  "is_active" boolean,
  "created_at" timestamptz,
  "updated_at" timestamptz
);

drop table if exists public."vehicle_makers" cascade;
create table public."vehicle_makers" (
  "id" bigint,
  "name" text,
  "is_active" boolean,
  "created_at" timestamptz,
  "updated_at" timestamptz
);

drop table if exists public."vehicle_models" cascade;
create table public."vehicle_models" (
  "id" bigint,
  "maker_id" bigint,
  "name" text,
  "is_active" boolean,
  "created_at" timestamptz,
  "updated_at" timestamptz
);

drop table if exists public."work_details" cascade;
create table public."work_details" (
  "id" bigint,
  "work_name" text,
  "line_no" bigint,
  "side" text,
  "part" text,
  "work_type" text,
  "created_at" timestamptz
);

drop table if exists public."work_orders" cascade;
create table public."work_orders" (
  "id" bigint,
  "work_name" text,
  "car_maker" text,
  "car_model" text,
  "car_number" text,
  "phone_number" text,
  "car_year" text,
  "vin" text,
  "mileage" text,
  "color_code" text,
  "inbound_date" date,
